import boto3
from botocore.exceptions import ClientError
from datetime import datetime

sqs = boto3.client('sqs')

def publish_message(queue_url, message_body):
    try:
        response = sqs.send_message(
            QueueUrl=queue_url,
            MessageBody=message_body
        )
        print(f'Message sent: {response["MessageId"]}')
    except ClientError as e:
        if e.response['Error']['Code'] == 'NonExistentQueue':
            print(e)
        else:
            raise

def main():
    # Replace with your SQS queue URL
    sqs_queue_url = 'https://sqs.us-west-2.amazonaws.com/123456789012/pii-data-queue'

    # Prepare a sample user data message
    user_data = {
        "id": 1,
        "name": "John Doe",
        "email": "john.doe@example.com",
        "phone_number": "+1234567890",
        "address": {"street": "123 Main St", "city": "Anytown", "state": "CA", "zip_code": "12345"}
    }

    # Serialize the message body to JSON
    message_body = dict(user_data)
    message_body_str = str(message_body)

    # Publish the message
    publish_message(sqs_queue_url, message_body_str)

if __name__ == "__main__":
    main()